1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = {
4	  customer: { yearsWithMHPCO: number };
5	  steps: Step[];
6	};
7	
8	const PROCESSING_FEE = 5;
9	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
10	const ITEM_BASE: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_BASE = 60;
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	
23	const itemBase = (item: Item): number => ITEM_BASE[item.type];
24	
25	const groupCountsByType = (items: Item[]): Map<string, number> => {
26	  const counts = new Map<string, number>();
27	  for (const item of items) {
28	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
29	  }
30	  return counts;
31	};
32	
33	const baseForGroup = (type: string, count: number): number => {
34	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
35	    return COMPONENT_BLOCK_BASE;
36	  }
37	  return count * ITEM_BASE[type];
38	};
39	
40	const calculatePolicyBase = (items: Item[]): number => {
41	  let total = 0;
42	  for (const [type, count] of groupCountsByType(items)) {
43	    total += baseForGroup(type, count);
44	  }
45	  return total;
46	};
47	
48	const roundUpInMHPCOsFavor = (amount: number): number => Math.ceil(amount);
49	
50	const quotePremium = ({ items }: Step): number => {
51	  const policyBase = calculatePolicyBase(items);
52	  const firstContractSurcharge = policyBase * FIRST_CONTRACT_SURCHARGE_RATE;
53	  const rawPremium = policyBase + firstContractSurcharge + PROCESSING_FEE;
54	  return roundUpInMHPCOsFavor(rawPremium);
55	};
56	
57	export const runScenario = ({ steps }: Scenario): { results: unknown[] } => {
58	  const results = steps.map((step) => ({ premium: quotePremium(step) }));
59	  return { results };
60	};
